var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...큭.","JPN":"……くっ。","ENG":"...Kgh.","TWN":"……咳。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"울브즈베인이... 왜 갑자기 이렇게 무겁지?","JPN":"ウルブズベインが……急に重たくなった？","ENG":"Why does Wolvesbane... suddenly feel so heavy?","TWN":"狼之災禍……為什麼突然變得這麼沉重……？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"이제 효과가 나타나기 시작한 모양이네요.","JPN":"そろそろ効果が出始めたようですね。","ENG":"It seems the effects are finally beginning to show.","TWN":"效果開始顯現了。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐...?","JPN":"何だって……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"운명을 끊어내는 흰 서리꽃이, 그 몸 안에서 늑대의 힘을 끊어내고 있어요.","JPN":"運命を断ち切る白い霜の花が、その体の中からオオカミの力を断ち切っているのです。","ENG":"The white frost flower that severs fate is cutting off the Wolf's power from within your body.","TWN":"斬斷命運的白霜花，正在切斷你體內狼的力量。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신은 이제 곧, 늑대가 아닌 평범한 인간이 되겠죠.","JPN":"あなたはもうすぐオオカミではない、普通の人間になるでしょう。","ENG":"Before long, you will become an ordinary human and no longer a Wolf.","TWN":"你很快就不再是狼，而只是普通的人類。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아무리 버티고 발버둥 쳐도 시간은 당신 편이 아니란 뜻이랍니다.","JPN":"どんなに耐えてあがいても、時間はあなたの味方ではないということです。","ENG":"No matter how much you endure and struggle, time is not on your side.","TWN":"無論你怎麼掙扎，時間都不站在你這邊。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"팔 하나를 잘라내면 다른 하나가 자라나. 이런 식으론 파고들 수 없겠어.","JPN":"腕を一本斬るともう一本が生えてくる。このままじゃ懐に入り込めない。","ENG":"If I cut off one arm, another one just grows right back. I can't break through like this.","TWN":"只要斬斷一隻手，另一隻就會再長出來。這樣無法突破。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그렇다면...","JPN":"それなら……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"레거시 디바이스 활성화.","JPN":"レガシーデバイス活性化。","ENG":"Legacy Device activated.","TWN":"啟動傳統設備。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"울브즈베인, 바라밀 명도.","JPN":"ウルブズベイン、波羅蜜命刀。","ENG":"Wolvesbane, Sword of Paramita.","TWN":"狼之災禍，波羅蜜命刀。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"윽...","JPN":"うっ……","ENG":"Ngh...","TWN":"唔……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"피하지 않고 과감하게 공격했지만, 정작 당신의 공격은 빗나갔네요.","JPN":"避けずに大胆な攻撃をしかけましたが、外れてしまいましたね。","ENG":"You attacked boldly without trying to evade, yet your strike missed.","TWN":"雖然沒有閃避果敢進攻，但你的攻擊落空了。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"오른손이 움직이지 않는 게 느껴지나요? 희망은 잘려나간 힘줄을 대신해주지 않아요.","JPN":"右手が動かないのが分かりますか？　希望は斬られた筋肉の代わりにはなってくれません。","ENG":"Can you feel that your right hand won't move? Hope cannot replace severed tendons.","TWN":"感覺到右手無法動彈了嗎？希望無法取代被切斷的筋脈。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그런 말장난으론 아무것도 바꿀 수 없죠.","JPN":"こういう言葉遊びでは何も変えられないでしょう？","ENG":"Wordplay like that won't change anything.","TWN":"光靠那種話，無法改變任何事。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...그래. 희망이 내 손을 대신 움직여줄 순 없겠지.","JPN":"……そうだね。希望が右手を動かしてはくれることはないよね。","ENG":"...Right. Hope won't make my right hand move again.","TWN":"……是啊，希望無法讓我的右手動起來。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"공간이 무너지고 있어...?","JPN":"空間が崩れている……？","ENG":"Is the space collapsing...?","TWN":"空間在崩壞……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그 사제는 어디로 사라졌지?!","JPN":"あの人はどこに消えちゃったの！？","ENG":"Where did he disappear to?!","TWN":"那個人去哪了？！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"...벨레스는 처음부터 없었어. 그건 거울에 비친 환영일 뿐이야.","JPN":"……ヴェレスは最初からいなかったよ。あれは反射した幻影だから。","ENG":"...Veles was never here to begin with. That was only a reflected illusion.","TWN":"……貝雷斯從一開始就不存在，那只是反射的幻影。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저건 나잖아? 이게 어떻게 된 거야?","JPN":"あれは私？　どうなってるの？","ENG":"That's me. What's going on?","TWN":"那不是我嗎？這到底怎麼回事？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"울브즈베인이. 선배가 그 남자의 거울을 부순 거야.","JPN":"ウルブズベインが。先輩があの男の鏡を壊したの。","ENG":"Wolvesbane. Mina destroyed that man's mirror.","TWN":"狼之災禍，是前輩擊碎了那男人的鏡子。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그리고 나 역시, 그 남자가 너흴 가두기 위해 준비한 거울들 중 하나.","JPN":"そして私も、あの男があなたたちを閉じ込めるために用意した鏡の一つ。","ENG":"And I'm also one of the mirrors he prepared to trap you.","TWN":"而我，也是那男人用來困住你們的其中一面鏡子。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"그림자 전당에서 보았던 너 자신을 기억해?","JPN":"影の殿堂で見たあなた自身のことを覚えてる？","ENG":"Do you remember the version of yourself you saw in the Shadow Palaces?","TWN":"還記得你在暗影殿堂看到的自己嗎？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"...아!","JPN":"……あ！","ENG":"...Ah!","TWN":"……啊！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};